<template>
	<view>
		<page-head :title="title"></page-head>
		<view class="uni-padding-wrap uni-common-mt">
			<view class="uni-btn-v"><button type="primary" @click="openDB">жү“ејҖж•°жҚ®еә“test.db</button></view>
			<view class="uni-btn-v"><button type="primary" @click="executeSQL">еҲӣе»әиЎЁdatabaseеҸҠжҸ’е…Ҙж•°жҚ®</button></view>
			<view class="uni-btn-v"><button type="primary" @click="selectSQL">жҹҘиҜўиЎЁdatabaseзҡ„ж•°жҚ®</button></view>
			<view class="uni-btn-v"><button type="primary" @click="droptable">еҲ йҷӨиЎЁdatabase</button></view>
			<view class="uni-btn-v"><button type="primary" @click="closeDB">е…ій—ӯж•°жҚ®еә“test.db</button></view>
			<view class="uni-btn-v"><button type="primary" @click="isOpenDB">жҹҘиҜўжҳҜеҗҰжү“ејҖж•°жҚ®еә“</button></view>
			
			
			
			
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			title: 'SQLite'
		};
	},
	methods: {
		openDB: function() {
			plus.sqlite.openDatabase({
				name: 'first',
				path: '_doc/test.db',
				success: function(e) {
					plus.nativeUI.alert('жү“ејҖж•°жҚ®еә“test.dbжҲҗеҠҹ ');
				},
				fail: function(e) {
					plus.nativeUI.alert('жү“ејҖж•°жҚ®еә“test.dbеӨұиҙҘ: ' + JSON.stringify(e));
				}
			});
		},
		// жү§иЎҢSQLиҜӯеҸҘ
		executeSQL: function() {
			plus.sqlite.executeSql({
				name: 'first',
				sql: 'create table if not exists database("name" CHAR(110),"sex" CHAR(10),"age" INT(11))',
				success: function(e) {
					plus.sqlite.executeSql({
						name: 'first',
						sql: "insert into database values('еҪҰ','еҘі','7000')",
						success: function(e) {
							plus.nativeUI.alert('еҲӣе»әиЎЁtableе’ҢжҸ’е…Ҙж•°жҚ®жҲҗеҠҹ');
						},
						fail: function(e) {
							plus.nativeUI.alert('еҲӣе»әиЎЁtableжҲҗеҠҹдҪҶжҸ’е…Ҙж•°жҚ®еӨұиҙҘ: ' + JSON.stringify(e));
						}
					});
				},
				fail: function(e) {
					plus.nativeUI.alert('еҲӣе»әиЎЁtableеӨұиҙҘ: ' + JSON.stringify(e));
				}
			});
		},
		// жҹҘиҜўSQLиҜӯеҸҘ
		selectSQL: function() {
			plus.sqlite.selectSql({
				name: 'first',
				sql: 'select * from database',
				success: function(e) {
					plus.nativeUI.alert('жҹҘиҜўSQLиҜӯеҸҘжҲҗеҠҹ: ' + JSON.stringify(e));
				},
				fail: function(e) {
					plus.nativeUI.alert('жҹҘиҜўSQLиҜӯеҸҘеӨұиҙҘ: ' + JSON.stringify(e));
				}
			});
		},
		// еҲ йҷӨиЎЁ
		droptable: function() {
			plus.sqlite.executeSql({
				name: 'first',
				sql: 'drop table database',
				success: function(e) {
					plus.nativeUI.alert('еҲ йҷӨиЎЁdatabaseжҲҗеҠҹ');
				},
				fail: function(e) {
					plus.nativeUI.alert('еҲ йҷӨиЎЁdatabaseеӨұиҙҘ: ' + JSON.stringify(e));
				}
			});
		},
		// е…ій—ӯж•°жҚ®еә“
		closeDB: function() {
			plus.sqlite.closeDatabase({
				name: 'first',
				success: function(e) {
					plus.nativeUI.alert('е…ій—ӯж•°жҚ®еә“жҲҗеҠҹ');
				},
				fail: function(e) {
					plus.nativeUI.alert('е…ій—ӯж•°жҚ®еә“еӨұиҙҘ: ' + JSON.stringify(e));
				}
			});
		},
		isOpenDB: function() {
			if (
				plus.sqlite.isOpenDatabase({
					name: 'first',
					path: '_doc/test.db'
				})
			) {
				plus.nativeUI.alert('Opened!');
			} else {
				plus.nativeUI.alert('Unopened!');
			}
		}
	}
};
</script>

<style>
	.uni-btn-v {
		margin: 20rpx 0;
		padding: 0;
	}
</style>
